import json
import requests

def lambda_handler(event, context):
    # Parse agent input
    task = json.loads(event['input']['task'])
    query = task.get('searchQuery', '')

    # Call search API (Tavily example)
    search_response = requests.post(
        'https://api.tavily.com/search',
        json={'api_key': 'YOUR_TAVILY_KEY', 'query': query, 'max_results': 5}
    ).json()

    # Return Bedrock Action Group format
    return {
        'task': {
            'finalAnswer': f"Found {len(search_response['results'])} sources for '{query}'",
            'completionStatus': 'COMPLETED'
        },
        'response': {
            'sources': [r['url'] for r in search_response['results']],
            'snippets': [r['content'] for r in search_response['results']]
        }
    }

import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const AGENT_ID = 'YOUR_AGENT_ID';
const ALIAS_ID = 'YOUR_AGENT_ALIAS_ID';

async function invokeResearchAgent(query: string, sessionId: string) {
  const command = new InvokeAgentCommand({
    agentId: AGENT_ID,
    agentAliasId: ALIAS_ID,
    sessionId: sessionId,
    inputText: query,
    enableTrace: true,
  });

  const response = await client.send(command);
  let completion = '';

  for await (const chunk of response.completion!) {
    if (chunk.bytes) {
      completion += new TextDecoder().decode(chunk.bytes);
    }
  }

  return { response: completion, sessionId };
}

// Usage
invokeResearchAgent('Latest quantum computing breakthroughs', 'qc-research-001');

