import vex
import json

class VerifiedResearchSession:
    def __init__(self, session_id: str):
        self.session_id = session_id
        self.verified_history = []

    @vex.workflow(
        checks=['claim_accuracy', 'recency_check'],
        session_persistence=True
    )
    def query(self, question: str):
        # Bedrock agent call
        agent_response = invoke_bedrock_agent(question, self.session_id)

        # Verify with conversation history
        verified = vex.verify({
            'input': question,
            'agent_output': agent_response,
            'session_history': self.verified_history[-3:],  # Last 3 turns
            'domain': 'research'
        })

        self.verified_history.append({
            'query': question,
            'verified_output': verified.output,
            'sources': verified.metadata.get('sources', [])
        })

        return verified

# Usage
